return [
  { name: 'Barrel', url: 'https://barrel.nyc', focus: 'Digital Agency — Strategy, Design, Development' },
  { name: 'Instrument', url: 'https://www.instrument.com', focus: 'Digital Product Studio — Branding, UX, Engineering' },
  { name: 'Locomotive', url: 'https://locomotive.ca', focus: 'Award-Winning Web Design + Scroll Animations' },
  { name: 'Rally', url: 'https://www.rally.co', focus: 'Interactive Design + Optimization Agency' },
  { name: 'Webflow', url: 'https://webflow.com', focus: 'Web Design Platform — No-Code + Data Storytelling' }
].map(c => ({ json: c }));

const items = $input.all();
const results = items.map(item => {
  const html = item.json.body || item.json.data || '';
  const name = item.json.url || 'unknown';

  // Extract title
  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  const title = titleMatch ? titleMatch[1].trim() : '';

  // Extract meta description
  const descMatch = html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']/i);
  const description = descMatch ? descMatch[1].trim() : '';

  // Extract h1 tags
  const h1Matches = [...html.matchAll(/<h1[^>]*>([^<]+)<\/h1>/gi)];
  const h1s = h1Matches.map(m => m[1].trim()).filter(Boolean).slice(0, 3);

  // Extract h2 tags (section headings)
  const h2Matches = [...html.matchAll(/<h2[^>]*>([^<]+)<\/h2>/gi)];
  const h2s = h2Matches.map(m => m[1].trim()).filter(Boolean).slice(0, 6);

  // Extract CTA button text
  const ctaMatches = [...html.matchAll(/<(?:a|button)[^>]*class=["'][^"']*(?:btn|cta|button)[^"']*["'][^>]*>([^<]+)/gi)];
  const ctas = [...new Set(ctaMatches.map(m => m[1].trim()).filter(s => s.length > 1 && s.length < 60))].slice(0, 5);

  // Extract nav links
  const navMatches = [...html.matchAll(/<(?:nav|header)[^>]*>([\s\S]*?)<\/(?:nav|header)>/gi)];
  const navText = navMatches.map(m => m[1].replace(/<[^>]+>/g, ' ').trim()).join(' ');
  const navLinks = [...new Set(navText.split(/\s+/).filter(w => w.length > 3 && w.length < 20))].slice(0, 8);

  // Count social proof signals
  const testimonialCount = (html.match(/testimonial|review|client|quote/gi) || []).length;
  const caseStudyCount = (html.match(/case.?study|portfolio|work|project/gi) || []).length;
  const statsCount = (html.match(/\d+[%+×x]|\$[\d,]+|[\d,]+\+/g) || []).length;

  // Detect tech signals
  const hasWebflow = /webflow/i.test(html);
  const hasNextJS = /next\.js|__next/i.test(html);
  const hasReact = /react/i.test(html);
  const hasGTM = /googletagmanager/i.test(html);
  const hasHotjar = /hotjar/i.test(html);
  const hasSchema = /application\/ld\+json/i.test(html);

  return { json: {
    name,
    title,
    description,
    h1s,
    sections: h2s,
    ctas,
    navLinks,
    socialProof: { testimonialCount, caseStudyCount, statsCount },
    techStack: { hasWebflow, hasNextJS, hasReact, hasGTM, hasHotjar, hasSchema },
    htmlLength: html.length,
    scrapedAt: new Date().toISOString()
  }};
});

return results;

const items = $input.all();
const competitors = items.map(i => i.json);

// Aggregate best practices
const allCTAs = competitors.flatMap(c => c.ctas || []);
const ctaFreq = {};
allCTAs.forEach(cta => { ctaFreq[cta] = (ctaFreq[cta] || 0) + 1; });
const topCTAs = Object.entries(ctaFreq)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([text, count]) => ({ text, usedBy: count }));

const allSections = competitors.flatMap(c => c.sections || []);
const sectionFreq = {};
allSections.forEach(s => { sectionFreq[s] = (sectionFreq[s] || 0) + 1; });
const commonSections = Object.entries(sectionFreq)
  .filter(([, count]) => count >= 2)
  .sort((a, b) => b[1] - a[1])
  .map(([name, count]) => ({ name, usedBy: count }));

const schemaAdopters = competitors.filter(c => c.techStack?.hasSchema).length;
const hotjarAdopters = competitors.filter(c => c.techStack?.hasHotjar).length;
const gtmAdopters = competitors.filter(c => c.techStack?.hasGTM).length;

const report = {
  generatedAt: new Date().toISOString(),
  competitors,
  bestPractices: {
    topCTAs,
    commonSections,
    toolAdoption: {
      schemaMarkup: `${schemaAdopters}/${competitors.length} use schema markup`,
      hotjar: `${hotjarAdopters}/${competitors.length} use Hotjar`,
      googleTagManager: `${gtmAdopters}/${competitors.length} use GTM`
    },
    recommendations: [
      schemaAdopters >= 3 ? '✅ Schema markup: used by majority — MUST implement' : '⚠️ Schema markup: low adoption — competitive advantage if implemented',
      hotjarAdopters >= 3 ? '✅ Behavioral analytics (Hotjar/heatmaps): industry standard' : 'Consider adding behavioral analytics for UX insights',
      'Track H1 messaging angles used by top 3 performers',
      'Monitor CTA copy changes quarterly — top performers A/B test continuously',
      `Most common sections across competitors: ${commonSections.slice(0,3).map(s=>s.name).join(', ')}`
    ]
  }
};

return [{ json: report }];

